using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly PaymentGateway _gateway;

    public PaymentGatewayTests()
    {
        _gateway = new PaymentGateway();
    }

    // ── ChargeAsync ──────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidCard_ReturnsSuccessResult()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsNotNull(result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCard_ReturnsNonEmptyChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 100m);

        Assert.IsNotNull(result.ChargeId);
        Assert.AreNotEqual(string.Empty, result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync("tok_valid_visa", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync("tok_valid_visa", -10m));
    }

    [TestMethod]
    public async Task ChargeAsync_NullCardToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            async () => await _gateway.ChargeAsync(null!, 25m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyCardToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync(string.Empty, 25m));
    }

    [TestMethod]
    [DataRow("tok_card_declined")]
    [DataRow("tok_expired")]
    public async Task ChargeAsync_InvalidCard_ReturnsFailureResult(string token)
    {
        var result = await _gateway.ChargeAsync(token, 50m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    [DataRow(0.01)]
    [DataRow(999_999.99)]
    public async Task ChargeAsync_BoundaryAmounts_Succeeds(double amount)
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", (decimal)amount);

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public async Task ChargeAsync_TwoCharges_ReturnDistinctChargeIds()
    {
        var r1 = await _gateway.ChargeAsync("tok_valid_visa", 10m);
        var r2 = await _gateway.ChargeAsync("tok_valid_visa", 20m);

        Assert.AreNotEqual(r1.ChargeId, r2.ChargeId);
    }

    // ── RefundAsync ──────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessResult()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 75m);
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsNotNull(refund.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsNonEmptyRefundId()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 30m);
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsNotNull(refund.RefundId);
        Assert.AreNotEqual(string.Empty, refund.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            async () => await _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.RefundAsync(string.Empty));
    }

    [TestMethod]
    public async Task RefundAsync_NonExistentChargeId_ReturnsFailureResult()
    {
        var refund = await _gateway.RefundAsync("ch_does_not_exist");

        Assert.IsFalse(refund.Success);
    }

    [TestMethod]
    public async Task RefundAsync_DoubleRefund_SecondReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50m);
        var first = await _gateway.RefundAsync(charge.ChargeId);
        var second = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(first.Success);
        Assert.IsFalse(second.Success);
    }
}

